// And groups predicates with the AND operator between them.
func And(predicates ...predicate.Cargo) predicate.Cargo {
	return predicate.Cargo(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Cargo) predicate.Cargo {
	return predicate.Cargo(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Cargo) predicate.Cargo {
	return predicate.Cargo(sql.NotPredicates(p))
}
